SELECT (SUM(c.conceded_units) * 100.0) / NULLIF(SUM(s.shipped_units), 0) AS return_rate_pct FROM shipped_raw s LEFT JOIN concession_raw c ON c.asin = s.asin AND c.mapped_year = s.year AND c.mapped_month = s.month AND c.mapped_week = s.week WHERE s.item_name ILIKE '%iphone%' GROUP BY s.item_name HAVING SUM(s.shipped_units) > 0;